+fn default_regen_output_path() -> PathBuf {
+    let now_ms: u128 = SystemTime::now()
+        .duration_since(UNIX_EPOCH)
+        .map(|d| d.as_millis())
+        .unwrap_or(0);
+    let pid = std::process::id();
+
+    std::env::temp_dir()
+        .join("mcp-agent-mail-conformance")
+        .join(format!("python_reference_{now_ms}_{pid}.json"))
+}
